      "n": 13,
      "column": "left",
      "text": "Jo mehß famaitaſtim ſcho\nWeetu/ tapehz/ ka winno Brehe-\ntchanà leela irr preeſch ta KUN-\nGA/ un tas KUNGS irr muhs\nfuchtijis to famaitaht."
    },
    {
      "n": 14,
      "column": "left",
      "text": "Un Lats iſgahje/ un run-\nnaja us fatweem Snohteein/ kas\nwinna Meitas gribbeja apxeimt/\nun fazzija: Zelleetes un eite nohſt\nno fchaß Weetas / jo tas\nKUNGS famaitahß ſcho Pils-\nfahtu / bet wiꞥſch bija fatweem\nSnohteem itt ka Smeeklusrun-\nnadans."
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un kad Gaifina mettaß/\nſkubbinaja tee Engeti to Lattu/\nfazzidami: Zellees / nem tawu\nSeewu un tawas diwi Meitas /\nkas klahtu irr / ka tu eekſch fcha\nPilsfahta Noseeguma bohjá ne\neiji."
    },
    {
      "n": 16,
      "column": "left",
      "text": "Bet wiꞥſch fatwejahß/ tad\nfatwehre tee Wihri winna Roh-\nku/ un winna Seewas Rohku/\nun winna diwejo Meito Rohku/\ntapehz/ ka ta KUNGA Apscheh-\nloſchana pahr winnu bija/ un is-\nwedde to / un pamette to ahra\npreeſch Pilsfahta."
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un kad tee tohs bij ahra\niſwedduschi/ tad fazzija wiꞥſch:\nIsglahb jelle tawu Dſihwibu /\nne atſkattees atpakkaß/ un ne ſtah-\nwi ſchinni wiſſá Klajumá / is-\nglahbees Kalná/ ka tu jaſchu boh-\njá ne eijt."
    },
    {
      "n": 18,
      "column": "left",
      "text": "Un Lats fazzija us teem /\nNe/ inhoſams Kungs."
    },
    {
      "n": 19,
      "column": "left",
      "text": "Raugi jelle/ taws Kalps\nirr Schehlaſtibu atraddis tawás"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Azziß/ un tawa Apschehloſ-\nko tu pee man darrijis effi/\nnu Dſihwibn iglahbdan\nwarren leela / bet es ne\nglahbtees Kalna Wirſù/\njaſchu kahds Launums ne a\nun es ne mirſiu."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Redſi jelle ſchiß Pil-\nirr tuwu klaht/ ka es uhs\nwarru behgt/ un ta irr ma-\nes jelle tur glahbjohß / neg\nirr masa/ka es dſihws palee"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Un wiꞥſch fazzija u\nReds/ es arridsan ſchinni\neſimu tew uſluhkojis / ue fan-\ndans to Pilsfahtu / no ka\nfazzijis."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Steidſees / glahbee-\npatt/ jo es ne warru ne fo da-\nteekams tu nhßturren effi n\nTadeht tappe ta Pils-\nWahrdß nosaukts Joára."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Ta Saule bij uſle-\nkad Lats Joára nahze."
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un tas KUNGS liſſe-\nSodomu un Gomorrn ſa-\nnn Ugguni liht no ta KUNG-\nDebbetim."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un famaitaja wiﬀai\npaſchus Pilsfahtus / un wi-\nKlajumu / un wiﬀus Pils-\nEedsihwotajus/ ir tohs Seu-\nAugtus."
    },
    {
      "n": 26,
      "column": "right",
      "text": "Un winna Seeiva at-\ntijahß atpakkaß/ un tappe /\nSahls-Stabbu."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Un Ahbräams zehlah-\nagri us to Weetu / fur w-\npreeſch ta KUNGA Waig-\nstahwejis."
    }
  ],
